<div class="stats-grid"><div class="stat-card primary"><span>Wallet Balance</span><h2><?= money((float)$user['balance']) ?></h2><p>Available amount in your wallet.</p></div><div class="stat-card"><span>Unread Notifications</span><h2><?= (int)$unreadCount ?></h2><p>Stay updated on your account activity.</p></div><div class="stat-card"><span>Quick Tools</span><p><a href="<?= base_url('index.php?route=wallet/bill-payment') ?>">Pay Bills</a> • <a href="<?= base_url('index.php?route=wallet/recharge') ?>">Recharge</a></p></div><div class="stat-card"><span>Account</span><h2><?= e($user['status']) ?></h2><p>Profile and wallet status</p></div></div><div class="grid-2 section-gap"><div class="card"><div class="card-head between"><h3>Recent Transactions</h3><a href="<?= base_url('index.php?route=transactions') ?>">View all</a></div><div class="table-wrap"><table><thead><tr><th>Ref</th><th>Type</th><th>Amount</th><th>Status</th></tr></thead><tbody><?php foreach ($recentTransactions as $tx): ?><tr><td><?= e($tx['reference_no']) ?></td><td><?= e(ucwords(str_replace('_', ' ', $tx['type']))) ?></td><td class="<?= $tx['direction']==='credit' ? 'text-success' : 'text-danger' ?>"><?= $tx['direction']==='credit' ? '+' : '-' ?><?= money((float)$tx['amount']) ?></td><td><span class="badge"><?= e($tx['status']) ?></span></td></tr><?php endforeach; ?><?php if (!$recentTransactions): ?><tr><td colspan="4">No transactions found.</td></tr><?php endif; ?></tbody></table></div></div><div class="card"><div class="card-head between"><h3>Notifications</h3><a href="<?= base_url('index.php?route=notifications') ?>">View all</a></div><div class="notification-list"><?php foreach ($notifications as $note): ?><div class="note-item"><strong><?= e($note['title']) ?></strong><p><?= e($note['message']) ?></p><small><?= e($note['created_at']) ?></small></div><?php endforeach; ?><?php if (!$notifications): ?><p>No notifications yet.</p><?php endif; ?></div></div></div>
